Context:
Every plugin that reads auth tokens persists them to `globalThis.__openTabs.tokenCache` to survive adapter re-injection. The pattern is byte-for-byte identical across 15+ plugins. Example from plugins/discord/src/discord-api.ts:

```typescript
const getPersistedToken = (): string | null => {
  try {
    const ns = (globalThis as Record<string, unknown>).__openTabs as Record<string, unknown> | undefined;
    const cache = ns?.tokenCache as Record<string, string | undefined> | undefined;
    return cache?.discord ?? null;
  } catch {
    return null;
  }
};

const setPersistedToken = (token: string): void => {
  try {
    const g = globalThis as Record<string, unknown>;
    if (!g.__openTabs) g.__openTabs = {};
    const ns = g.__openTabs as Record<string, unknown>;
    if (!ns.tokenCache) ns.tokenCache = {};
    const cache = ns.tokenCache as Record<string, string | undefined>;
    cache.discord = token;
  } catch {}
};

const clearPersistedToken = (): void => {
  try {
    const ns = (globalThis as Record<string, unknown>).__openTabs as Record<string, unknown> | undefined;
    const cache = ns?.tokenCache as Record<string, string | undefined> | undefined;
    if (cache) cache.discord = undefined;
  } catch {}
};
```

Some plugins store strings (Discord, Supabase), others store objects (Jira stores `{ accountId, cloudId }`, Notion stores `{ userId, spaceId }`, Linear stores `{ userAccountId, userId, ... }`). The generic T parameter handles both.

Changes:
Add after line 136 in storage.ts:
```typescript
export const getAuthCache = <T>(namespace: string): T | null => {
  try {
    const ns = (globalThis as Record<string, unknown>).__openTabs as Record<string, unknown> | undefined;
    const cache = ns?.tokenCache as Record<string, unknown> | undefined;
    return (cache?.[namespace] as T) ?? null;
  } catch {
    return null;
  }
};

export const setAuthCache = <T>(namespace: string, value: T): void => {
  try {
    const g = globalThis as Record<string, unknown>;
    if (!g.__openTabs) g.__openTabs = {};
    const ns = g.__openTabs as Record<string, unknown>;
    if (!ns.tokenCache) ns.tokenCache = {};
    (ns.tokenCache as Record<string, unknown>)[namespace] = value;
  } catch {}
};

export const clearAuthCache = (namespace: string): void => {
  try {
    const ns = (globalThis as Record<string, unknown>).__openTabs as Record<string, unknown> | undefined;
    const cache = ns?.tokenCache as Record<string, unknown> | undefined;
    if (cache) cache[namespace] = undefined;
  } catch {}
};
```

Add to the Storage exports block in index.ts (around line 215):
```typescript
export {
  clearAuthCache,
  getAuthCache,
  ...
} from './storage.js';
```

Constraints:
- Do NOT change any existing functions in storage.ts
- Do NOT add JSDoc that references specific plugins (keep it generic)
- Follow the existing error handling pattern (try-catch, silently ignore, no log.warn for these — consistent with how plugins already use this pattern silently)
- The namespace parameter is the plugin name string (e.g., 'discord', 'jira')

